import{_ as t,o as d,c as o,a5 as c}from"./chunks/framework.QFIuQCaY.js";const m=JSON.parse('{"title":"IMPL-005 — CI/CD 파이프라인 구축","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/impl-cicd-pipeline.md","filePath":"decision-log/impl-cicd-pipeline.md"}'),a={name:"decision-log/impl-cicd-pipeline.md"};function s(n,e,i,r,l,p){return d(),o("div",null,[...e[0]||(e[0]=[c(`<h1 id="impl-005-—-ci-cd-파이프라인-구축" tabindex="-1">IMPL-005 — CI/CD 파이프라인 구축 <a class="header-anchor" href="#impl-005-—-ci-cd-파이프라인-구축" aria-label="Permalink to &quot;IMPL-005 — CI/CD 파이프라인 구축&quot;">​</a></h1><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>날짜</td><td>2026-03-23</td></tr><tr><td>브랜치</td><td><code>chore/lint-setup</code>, <code>chore/ci-setup</code>, <code>chore/npm-release</code></td></tr><tr><td>상위 결정</td><td><a href="/rest-domain-state-manager/decision-log/ard-0001.html">ARD-0001</a></td></tr><tr><td>상태</td><td>완료</td></tr></tbody></table><h2 id="_1-문제-정의" tabindex="-1">1. 문제 정의 <a class="header-anchor" href="#_1-문제-정의" aria-label="Permalink to &quot;1. 문제 정의&quot;">​</a></h2><h3 id="_1-1-코드-품질-자동화-부재" tabindex="-1">1.1 코드 품질 자동화 부재 <a class="header-anchor" href="#_1-1-코드-품질-자동화-부재" aria-label="Permalink to &quot;1.1 코드 품질 자동화 부재&quot;">​</a></h3><p><code>package.json</code> 에 <code>eslint: ^9.0.0</code> 과 <code>prettier: ^3.5.0</code> 이 <code>devDependencies</code> 에 선언되어 있었으나, 설정 파일이 없는 깡통 상태였다. <code>npm run lint</code> 를 실행해도 아무것도 검사하지 않고 통과했다. 또한 커밋 메시지 형식에 대한 강제 수단이 없어 자동화된 버전 결정과 CHANGELOG 생성이 불가능했다.</p><h3 id="_1-2-수동-배포-프로세스" tabindex="-1">1.2 수동 배포 프로세스 <a class="header-anchor" href="#_1-2-수동-배포-프로세스" aria-label="Permalink to &quot;1.2 수동 배포 프로세스&quot;">​</a></h3><p>NPM 배포가 수동으로 이루어졌다. 버전 번호를 직접 올리고, CHANGELOG를 수동으로 작성하고, <code>npm publish</code> 를 직접 실행하는 방식은 실수를 유발하고 배포 이력 추적을 어렵게 한다.</p><h2 id="_2-설계-결정" tabindex="-1">2. 설계 결정 <a class="header-anchor" href="#_2-설계-결정" aria-label="Permalink to &quot;2. 설계 결정&quot;">​</a></h2><p>파이프라인을 3단계로 구성했다.</p><table tabindex="0"><thead><tr><th>단계</th><th>내용</th></tr></thead><tbody><tr><td>4-A</td><td>ESLint Flat Config + Prettier 도입</td></tr><tr><td>4-B</td><td>GitHub Actions CI/Release 워크플로우</td></tr><tr><td>4-C</td><td>semantic-release 기반 NPM 자동 배포</td></tr></tbody></table><h3 id="_2-1-린팅-—-eslint-9-flat-config-채택" tabindex="-1">2.1 린팅 — ESLint 9 Flat Config 채택 <a class="header-anchor" href="#_2-1-린팅-—-eslint-9-flat-config-채택" aria-label="Permalink to &quot;2.1 린팅 — ESLint 9 Flat Config 채택&quot;">​</a></h3><p>ESLint 9는 기존 <code>.eslintrc.*</code> 방식을 Flat Config(<code>eslint.config.js</code>)로 대체했다. 이미 9.x가 설치되어 있으므로 신규 방식을 채택한다. Biome은 생태계 호환성과 이미 설치된 ESLint + Prettier 조합이 있다는 이유로 채택하지 않았다.</p><p><strong>규칙 선택 근거:</strong></p><ul><li><code>no-unused-vars</code> — import 해놓고 쓰지 않는 코드를 CI에서 잡는다. <code>_</code> 로 시작하는 인자는 콜백의 무시 패턴(<code>(_event) =&gt; {}</code>)을 위해 예외 처리.</li><li><code>no-console</code> — <code>console.log</code> 가 프로덕션 번들에 포함되는 것을 방지한다. <code>debug/warn/error</code> 는 허용 목록에 둔다. <code>src/debug/</code> 가 의도적으로 <code>console.debug</code> 를 사용하고 에러 메시지 모듈이 <code>console.warn</code> 을 쓰기 때문이다.</li><li><code>jsdoc/check-tag-names</code> — <code>@module</code> 을 허용 목록에 명시했다. TypeDoc이 사용하는 커스텀 태그이기 때문이다.</li></ul><p><strong>첫 린트 실행 결과 수정 이력:</strong></p><table tabindex="0"><thead><tr><th>에러</th><th>파일</th><th>원인</th><th>해결</th></tr></thead><tbody><tr><td><code>no-case-declarations</code></td><td><code>api-proxy.js:359,370</code></td><td><code>switch</code> <code>case</code> 블록에 스코프 없는 <code>const</code> 선언</td><td><code>splice</code> case에 <code>{}</code> 블록 명시</td></tr><tr><td><code>no-useless-escape</code></td><td><code>debug-channel.js:612</code></td><td>HTML 템플릿 문자열의 <code>&lt;\\/script&gt;</code></td><td><code>&lt;/script&gt;</code> 로 교체</td></tr><tr><td><code>no-unused-vars</code></td><td><code>api-handler.js:50</code></td><td>리팩토링 과정에서 미사용 <code>ERR</code> import 잔류</td><td>import 라인 삭제</td></tr><tr><td><code>no-console</code></td><td><code>DomainState.js:643</code></td><td><code>log()</code> 메서드의 의도된 <code>console.log</code></td><td><code>eslint-disable-next-line</code> 처리</td></tr></tbody></table><p>최종 결과: <strong>에러 0개, 경고 20개 (JSDoc @param 설명 누락만 남음)</strong>. 경고는 CI에서 blocking하지 않는다.</p><h3 id="_2-2-github-actions-—-두-워크플로우-설계" tabindex="-1">2.2 GitHub Actions — 두 워크플로우 설계 <a class="header-anchor" href="#_2-2-github-actions-—-두-워크플로우-설계" aria-label="Permalink to &quot;2.2 GitHub Actions — 두 워크플로우 설계&quot;">​</a></h3><p><strong>CI 워크플로우 (<code>ci.yml</code>):</strong></p><ul><li>트리거: <code>main</code>, <code>develop</code>, <code>feature/**</code>, <code>fix/**</code>, <code>refactor/**</code> 브랜치 push + <code>main</code>, <code>develop</code> 대상 PR</li><li>Node.js 20/22 매트릭스 — 소비자가 어떤 버전을 사용할지 알 수 없으므로 LTS와 현재 안정 버전 양쪽을 검증한다.</li><li><code>npm ci</code> — <code>package-lock.json</code> 을 수정하지 않아 재현 가능한 설치를 보장한다.</li></ul><p><strong>Release 워크플로우 (<code>release.yml</code>):</strong></p><ul><li>트리거: <code>main</code> push만. <code>develop</code>, <code>feature/</code> 에서는 절대 릴리즈가 일어나지 않는다.</li><li><code>concurrency.cancel-in-progress: true</code> — 연속 push 시 이전 워크플로우를 취소하여 중복 릴리즈를 방지한다.</li><li><code>fetch-depth: 0</code> — semantic-release가 마지막 릴리즈 태그 이후 전체 커밋 히스토리를 분석한다. 얕은 클론(<code>fetch-depth: 1</code>)에서는 히스토리가 잘려 버전 결정 실패.</li><li><code>permissions: contents: write</code> — semantic-release가 GitHub에 태그를 push하고 Release를 생성하려면 쓰기 권한이 필요하다.</li></ul><h3 id="_2-3-semantic-release-—-자동-버전-결정-및-npm-배포" tabindex="-1">2.3 semantic-release — 자동 버전 결정 및 NPM 배포 <a class="header-anchor" href="#_2-3-semantic-release-—-자동-버전-결정-및-npm-배포" aria-label="Permalink to &quot;2.3 semantic-release — 자동 버전 결정 및 NPM 배포&quot;">​</a></h3><p>Conventional Commits 메시지를 파싱하여 버전을 자동 결정한다.</p><table tabindex="0"><thead><tr><th>커밋 타입</th><th>버전 영향</th></tr></thead><tbody><tr><td><code>feat:</code></td><td>minor (0.5.0 → 0.6.0)</td></tr><tr><td><code>fix:</code>, <code>perf:</code>, <code>refactor:</code>, <code>revert:</code></td><td>patch (0.5.0 → 0.5.1)</td></tr><tr><td><code>BREAKING CHANGE:</code> 본문 포함</td><td>major (0.5.0 → 1.0.0)</td></tr><tr><td><code>docs:</code>, <code>test:</code>, <code>chore:</code></td><td>변경 없음</td></tr></tbody></table><p><strong>플러그인 실행 순서:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commit-analyzer → release-notes-generator → @semantic-release/changelog</span></span>
<span class="line"><span>→ @semantic-release/npm → @semantic-release/git → @semantic-release/github</span></span></code></pre></div><p><code>@semantic-release/git</code> 이 <code>CHANGELOG.md</code> 와 <code>package.json</code> 변경사항을 <code>chore(release): X.Y.Z [skip ci]</code> 메시지로 커밋한다. <code>[skip ci]</code> 가 없으면 이 커밋이 다시 Release 워크플로우를 트리거하는 무한 루프가 발생한다.</p><h3 id="_2-4-sideeffects-false-추가-근거" tabindex="-1">2.4 <code>&quot;sideEffects&quot;: false</code> 추가 근거 <a class="header-anchor" href="#_2-4-sideeffects-false-추가-근거" aria-label="Permalink to &quot;2.4 \`&quot;sideEffects&quot;: false\` 추가 근거&quot;">​</a></h3><p>번들러는 기본적으로 패키지 내 모든 코드를 번들에 포함시킨다. <code>sideEffects: false</code> 를 선언하면 번들러가 공격적인 Tree-shaking을 적용하여 소비자가 실제로 import한 심볼만 번들에 포함시킨다. 예를 들어 <code>DomainState</code> 만 import한 소비자의 번들에서 <code>DomainRenderer</code>, <code>FormBinder</code> 가 제거된다.</p><h3 id="_2-5-semantic-release-changelog-설치-주의사항" tabindex="-1">2.5 <code>@semantic-release/changelog</code> 설치 주의사항 <a class="header-anchor" href="#_2-5-semantic-release-changelog-설치-주의사항" aria-label="Permalink to &quot;2.5 \`@semantic-release/changelog\` 설치 주의사항&quot;">​</a></h3><p>이 패키지를 <code>package-lock.json</code> 과 함께 커밋하지 않으면 GitHub Actions의 <code>npm ci</code> 가 <code>Cannot find module &#39;@semantic-release/changelog&#39;</code> 에러를 낸다. <code>npm ci</code> 는 <code>package-lock.json</code> 에 없는 패키지를 설치하지 않기 때문이다. <strong>반드시 <code>package.json</code> 과 <code>package-lock.json</code> 을 함께 커밋해야 한다.</strong></p><h2 id="_3-결과" tabindex="-1">3. 결과 <a class="header-anchor" href="#_3-결과" aria-label="Permalink to &quot;3. 결과&quot;">​</a></h2><p><strong>브랜치 전략:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main          ← 릴리즈 전용. PR merge만 허용.</span></span>
<span class="line"><span>└── develop   ← 통합 브랜치</span></span>
<span class="line"><span>     ├── feature/xxx</span></span>
<span class="line"><span>     ├── fix/xxx</span></span>
<span class="line"><span>     └── refactor/xxx</span></span></code></pre></div><p><strong>최종 반영 파일:</strong></p><table tabindex="0"><thead><tr><th>파일</th><th>종류</th><th>내용</th></tr></thead><tbody><tr><td><code>eslint.config.js</code></td><td>신규</td><td>ESLint 9 Flat Config</td></tr><tr><td><code>.prettierrc</code></td><td>신규</td><td>프로젝트 포맷 규칙</td></tr><tr><td><code>commitlint.config.js</code></td><td>신규</td><td>Conventional Commits 강제</td></tr><tr><td><code>.github/workflows/ci.yml</code></td><td>신규</td><td>lint + test + format:check</td></tr><tr><td><code>.github/workflows/release.yml</code></td><td>신규</td><td>semantic-release 파이프라인</td></tr><tr><td><code>.releaserc.json</code></td><td>신규</td><td>semantic-release 플러그인 체인</td></tr><tr><td><code>.npmignore</code></td><td>신규</td><td>배포 tarball 제외 목록</td></tr><tr><td><code>package.json</code></td><td>수정</td><td>scripts, <code>sideEffects</code>, <code>engines</code>, devDeps</td></tr></tbody></table><p>커밋 한 번으로 lint → test → build → CHANGELOG 생성 → NPM 배포 → GitHub Release 생성까지 전 과정이 자동으로 완결된다.</p>`,38)])])}const g=t(a,[["render",s]]);export{m as __pageData,g as default};
